import{_ as r,o,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"10. Overtime","description":"","frontmatter":{"title":"10. Overtime","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime","employment","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/hours-of-work/10-overtime.md","filePath":"ebas/has-managers-admin/managers-admin/hours-of-work/10-overtime.md"}'),s={name:"ebas/has-managers-admin/managers-admin/hours-of-work/10-overtime.md"};function i(n,e,d,m,p,l){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_10-overtime" tabindex="-1">10. Overtime <a class="header-anchor" href="#_10-overtime" aria-label="Permalink to &quot;10. Overtime&quot;">​</a></h1><p><strong>10.1</strong> Where an Employee is required to work reasonable additional hours, they will be entitled to payment of overtime in accordance with the provisions of this clause.</p><p><strong>10.2</strong> Overtime, other than for time worked during the daylight savings change over period prescribed at subclause 49.1 of Section 1, means work that is performed:</p><p><strong>(a)</strong> by a full-time employee, where:</p><p><strong>(i)</strong> work is performed in excess of the ordinary agreed hours on a particular day; or,</p><p><strong>(ii)</strong> work is performed in excess of ordinary hours as prescribed in subclause 7.1 of Section 3; or</p><p><strong>(iii)</strong> work is performed in excess of twelve hours in any one shift,</p><p><strong>(b)</strong> by a part-time employee, where:</p><p><strong>(i)</strong> work is performed in excess of ordinary hours as prescribed in subclause 7.1 of Section 3; or</p><p><strong>(ii)</strong> the Employer directs the Employee to work additional hours beyond those agreed in clause 21.3 of Section 1, but excluding where an Employee is offered and accepts additional ordinary hours as described at subclause 21.10 (Additional Hours) of Section 1; or</p><p><strong>(iii)</strong> work is performed in excess of twelve hours in any one shift,</p><p><strong>10.3</strong> Only authorised overtime will be paid for at the following overtime rates:</p><p><strong>(a)</strong> For Overtime that arises pursuant to subclause 10.2(a) and 10.2(b)</p><p><strong>(i)</strong> 150% (based on 1/38th of the weekly salary set out in Schedule 3B) for the first two hours and 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>) thereafter</p><p><strong>(b)</strong> For Overtime outside a spread of 12 hours after commencing ordinary duty</p><p><strong>(i)</strong> 200% (based on 1/38th of the weekly salary set out in Schedule 3B)</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',17)])])}const c=r(s,[["render",i]]);export{u as __pageData,c as default};
